import ThemeToggle from "./ThemeToggle";
import { useState, useRef } from "react";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";
import ReCAPTCHA from "react-google-recaptcha";
import "./CSS/PatientLogin.css";

const Login = () => {
  const navigate = useNavigate();
  const [identifier, setIdentifier] = useState(""); // Email or Phone
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("user"); // 'admin', 'centre', 'user'
  const [error, setError] = useState("");
  const [recaptchaToken, setRecaptchaToken] = useState("");
  const recaptchaRef = useRef();

  const RECAPTCHA_SITE_KEY = process.env.REACT_APP_RECAPTCHA_SITE_KEY;

  // Handle reCAPTCHA change
  const handleRecaptchaChange = (token) => {
    setRecaptchaToken(token);
  };

  const handleLogin = async (e) => {
    e.preventDefault();

    if (!role || !identifier || !password) {
      setError("All fields are required.");
      return;
    }

    if (!recaptchaToken) {
      setError("Please complete the reCAPTCHA verification.");
      return;
    }

    let apiUrl = "";
    if (role === "user") {
      apiUrl = `${process.env.REACT_APP_BACKEND_URL}/api/users/login`;
    }

    try {
      const res = await axios.post(apiUrl, {
        identifier,
        password,
        recaptchaToken, // Include reCAPTCHA token
      });

      const token = res?.data?.token;
      if (!token) {
        setError("No token received from server.");
        setRecaptchaToken("");
        recaptchaRef.current.reset();
        return;
      }

      localStorage.setItem("token", token);

      if (role === "user") {
        localStorage.setItem("user", JSON.stringify(res.data?.user));
        localStorage.setItem("userToken", token);
        localStorage.setItem("userId", res.data.user.id);

        navigate("/user-dashboard");
      }
    } catch (err) {
      setError(err?.response?.data?.message || "Login failed.");
      setRecaptchaToken("");
      recaptchaRef.current.reset();
    }
  };

  return (
    <>
      {/* ================================== Account Page Start =========================== */}
      <section className="account d-flex" style={{ height: "100vh" }}>
        <div className="account__left d-md-flex d-none flx-align section-bg position-relative z-index-1 overflow-hidden">
          <div className="account-thumb">
            <img src="assets/images/services/Login.png" alt=""  loading="lazy"/>
            <div className="statistics animation bg-main text-center">
              <span className="statistics__text text-white font-14">
                Verified <br />
                Healthcare <br />
                Centre{" "}
              </span>
            </div>
          </div>
        </div>

        <div
          className="account__right padding-y-120 flx-align"
          style={{ marginTop: "-30px" }}
        >
          <div className="account-content ">
            <Link to="/" className="logo">
              <img
                src="assets/images/logo/BHARATLOGO-01.png"
                alt=""
                className="white-version"
              />
              <img
                src="assets/images/logo/BHARATLOGO-01.png"
                alt=""
                className="dark-version"
              />
            </Link>

            <div
              style={{
                display: "flex",
                gap: "15px",
                marginBottom: "10px",
                paddingTop: "-20px",
                marginTop: "10px",
                justifyContent:"center"
              }}
            >
              <button
                className="loginButton"
                style={{
                  backgroundColor: "#5E36F2",
                  color: "white",
                  borderRadius: "5px",
                  padding: "10px 20px",
                }}
              >
                Login as a Patient
              </button>
              {/* <Link to="/centre-login">
                <button
                  className="loginButton"
                  style={{
                    backgroundColor: "rgb(219 213 255)",
                    color: "rgb(94, 54, 242)",
                    borderRadius: "5px",
                    padding: "10px 20px",
                  }}
                >
                  Login as a Healthcare Centre
                </button>
              </Link> */}
            </div>

            {error && <div className="alert alert-danger">{error}</div>}
            <form onSubmit={handleLogin}>
              <div className="row gy-4">
                <div className="col-12">
                  <label
                    htmlFor="email"
                    className="form-label mb-2 font-18 font-heading fw-600"
                    style={{ fontFamily: "inter" }}
                  >
                    Email or Phone
                  </label>

                  <div className="position-relative">
                    <input
                      type="text"
                      className="common-input common-input--bg common-input--withIcon"
                      id="email"
                      placeholder="Enter email or phone"
                      value={identifier}
                      onChange={(e) => setIdentifier(e.target.value)}
                      required
                    />

                    <span className="input-icon">
                      <img src="assets/images/icons/envelope-icon.svg" alt=""  loading="lazy" />
                    </span>
                  </div>
                </div>

                <div className="col-12">
                  <label
                    htmlFor="your-password"
                    className="form-label mb-2 font-18 font-heading fw-600"
                    style={{ fontFamily: "inter" }}
                  >
                    Password
                  </label>

                  <div className="position-relative">
                    <input
                      type="password"
                      className="common-input common-input--bg common-input--withIcon"
                      id="your-password"
                      placeholder="Enter Your Password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                    />
                    <span
                      className="input-icon toggle-password cursor-pointer"
                      id="#your-password"
                    >
                      <img src="assets/images/icons/lock-icon.svg" alt=""  loading="lazy" />
                    </span>
                  </div>
                </div>

                {/* reCAPTCHA Section */}
                <div className="col-12">
                  <div className="d-flex justify-content-center">
                    <ReCAPTCHA
                      ref={recaptchaRef}
                      sitekey={RECAPTCHA_SITE_KEY}
                      onChange={handleRecaptchaChange}
                      onExpired={() => setRecaptchaToken("")}
                      onErrored={() => setRecaptchaToken("")}
                    />
                  </div>
                </div>

                <div className="col-12">
                  <div className="flx-between gap-1">
                    <Link
                      to="/forgot-password"
                      className="forgot-password text-decoration-underline text-main text-poppins font-14"
                    >
                      Forgot password?
                    </Link>
                  </div>
                </div>

                <div className="col-12">
                  <button
                    type="submit"
                    className="btn btn-main btn-lg w-100 pill"
                    disabled={!recaptchaToken}
                  >
                    Sign In
                  </button>
                </div>

                <div className="col-12 ">
                  <button
                    type="button"
                    style={{
                      backgroundColor: "rgb(219 213 255)",
                      color: "#7236f2",
                      borderRadius: "5px",
                      padding: "10px 20px",
                      height: "60px",
                    }}
                    onClick={() => navigate("/")}
                    className="btn-lg w-100 pill"
                  >
                    <i className="fa fa-arrow-left "></i> Back to Home
                  </button>
                </div>

                <div className="col-sm-12 mb-0">
                  <div className="have-account">
                    <p className="text font-14">
                      Not Registered?{" "}
                      <Link
                        className="link text-main text-decoration-underline fw-500"
                        to="/user-register"
                      >
                        Register
                      </Link>
                    </p>
                  </div>
                </div>
              </div>
            </form>
          </div>
        </div>
      </section>
      {/* ================================== Account Page End =========================== */}
    </>
  );
};

export default Login;