import React from "react";
import Progress from "../components/Progress";
import Login from "../components/Login";
import { SEO } from "../utils/SEO";
const LoginPage = () => {
  const can = window.location.href;

  return (

    <>
      <SEO
        title="4ceps | Login – Access Your Healthcare Account"
        description="Login to your 4ceps account to manage appointments, view bookings, update your profile and access healthcare services."
        url={can}
      />
      {/* Progress */}
      <Progress />

      {/* Login */}
      <Login />
    </>
  );
};

export default LoginPage;
